#include "soh_ap.h"

namespace rls::transpilers::soh_ap {

std::string SohApTranspiler::functionsPreamble() const {
	// Mirror the regions file: Rules re-exports the host rules, enum classes,
	// rule literals, and the Callable/Rule names the generated annotations reference.
	return
		"# Generated by RLS soh_ap transpiler\n"
		"from .Rules import *\n"
		"from .rls_match import rls_match_rule, rls_match_value\n"
		"\n"
		"if TYPE_CHECKING:\n"
		"    from ... import SohWorld\n";
}

std::string SohApTranspiler::pythonTypeName(rls::ast::Type type) const {
	using AT = rls::ast::Type;
	switch (type) {
		case AT::Bool: return "bool";
		case AT::Int: return "int";
		// A Condition/Callable lowers to a thunk invoked as `cond(bundle)`: it takes the
		// rule bundle and returns a Rule (see GenerateCallArgument / InvokeExpr).
		case AT::Condition:
		case AT::Callable: return "Callable[[tuple[Regions, \"SohWorld\"]], Rule]";
		default: break;
	}
	// Every other supported type is enum-valued; annotate it with the same class
	// renderEnumValue prefixes its values with, so signatures and values agree.
	if (auto cls = enumClassName(type)) {
		return *cls;
	}
	return "unsupported_type";
}

} // namespace rls::transpilers::soh_ap
